mapper.select:
select count(0)
from answer
where user_id=#{userId}
  and log_date=#{date}

select *
from answer
where user_id=#{userId}
  and log_date=#{date}
limit 1

select log_date, study_or_work_time, communicate_time, phone_play_time
from answer
where user_id=#{userId} and DATEDIFF(NOW(), log_date) < #{period}

select *
from answer
where user_id=#{userId}
order by log_date DESC;

select count(0)
from answer
where user_id = #{userId}
and log_date >= #{startTime}
and log_date < #{endTime}
